from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    sentences = []
    for subject, triples_list in subject_map.items():
        sentence = ""
        for i, (predicate, obj) in enumerate(triples_list):
            if predicate == "cityServed":
                sentence += f"{subject} serves the city of {obj}"
            elif predicate == "mayor":
                sentence += f"{subject} has a mayor of {obj}"
            elif predicate == "isPartOf":
                sentence += f"{subject} is part of {obj}"
            elif predicate == "operatingOrganisation":
                sentence += f"{subject} is operated by {obj}"
            elif predicate == "location":
                sentence += f"{subject} is located in {obj}"
            elif predicate == "elevationAboveTheSeaLevel":
                sentence += f"{subject} has an elevation of {obj} metres above sea level"
            elif predicate == "runwayLength":
                sentence += f"The length of the runway at {subject} is {obj} metres"
            elif predicate == "country":
                sentence += f"{subject} is located in {obj}"
            elif predicate == "capital":
                sentence += f"{subject} has a capital of {obj}"
            elif predicate == "language":
                sentence += f"{obj} is spoken in {subject}"
            elif predicate == "leader":
                sentence += f"{subject} has a leader of {obj}"
            elif predicate == "owner":
                sentence += f"{subject} is owned by {obj}"
            elif predicate == "1stRunwayLengthFeet":
                sentence += f"The length of the first runway at {subject} is {obj} feet"
            elif predicate == "1stRunwaySurfaceType":
                sentence += f"{subject} has a first runway surface type of {obj}"
            elif predicate == "3rdRunwayLengthFeet":
                sentence += f"{subject} has a third runway length of {obj} feet"
            elif predicate == "icaoLocationIdentifier":
                sentence += f"{subject} has an ICAO location identifier of {obj}"
            elif predicate == "locationIdentifier":
                sentence += f"{subject} has a location identifier of {obj}"
            elif predicate == "elevationAboveTheSeaLevelInFeet":
                sentence += f"{subject} has an elevation of {obj} feet above sea level"
            elif predicate == "iataLocationIdentifier":
                sentence += f"{subject} has an IATA location identifier of {obj}"
            elif predicate == "nativeName":
                sentence += f"{subject} has a native name of {obj}"
            elif predicate == "leaderParty":
                sentence += f"{subject} has a leader party of {obj}"
            elif predicate == "isPartOf":
                sentence += f"{subject} is a part of {obj}"
            elif predicate == "capital":
                sentence += f"{subject} has {obj} as its capital"
            else:
                sentence += f"{subject} has a {predicate} of {obj}"
            if i < len(triples_list) - 1:
                sentence += ", "
        sentences.append(sentence)

    # Try to connect related triples into a single sentence
    if len(sentences) > 1:
        return " and ".join(sentences) + "."
    else:
        return sentences[0] + "."

